      int Function(ffi.Pointer<lw_pc_t>, ffi.Pointer<LwPcObserver>,
          ffi.Pointer<ffi.Void>)>();

  /// Removes and destroys the pc's observer, if any.
  void lw_pc_remove_observer(
    ffi.Pointer<lw_pc_t> pc,
  ) {
    return _lw_pc_remove_observer(
      pc,
    );
  }

  late final _lw_pc_remove_observerPtr =
      _lookup<ffi.NativeFunction<ffi.Void Function(ffi.Pointer<lw_pc_t>)>>(
          'lw_pc_remove_observer');
  late final _lw_pc_remove_observer = _lw_pc_remove_observerPtr
      .asFunction<void Function(ffi.Pointer<lw_pc_t>)>();
}

/// One plane of a dmabuf-backed frame.
///
/// fd is NON-OWNING: owned by the producer (the decoder CAPTURE-queue pool).
/// It is valid only until the matching LwFrameRelease is invoked, and only
/// within a single pool_generation (the kernel reuses fd numbers after a
/// pool is torn down). Consumers MUST NOT close fd.
final class LwDmabufPlane extends ffi.Struct {
  /// non-owning; valid until release_cb
  @ffi.Int32()
  external int fd;

  /// byte offset of this plane within the dmabuf
  @ffi.Uint32()
  external int offset;

  /// row stride in bytes
  @ffi.Uint32()
  external int pitch;
}

/// A decoded frame, described by reference (zero copy).
///
/// `size` is sizeof(LwDmabufDescriptor) at the producer's compile time. A
/// consumer built against a different ABI minor MUST check `desc->size`
/// before reading any field beyond it: read min(sizeof(local), desc->size)
/// bytes, treat the remainder as absent. New fields only ever append.
///
/// `num_planes` is attacker/bug-reachable via the bitstream path upstream;
/// consumers MUST validate `num_planes <= LW_MAX_PLANES` before indexing
/// planes[] rather than trusting it.
final class LwDmabufDescriptor extends ffi.Struct {
  /// sizeof(LwDmabufDescriptor)
  @ffi.Uint32()
  external int size;

  /// DRM_FORMAT_*
  @ffi.Uint32()
  external int fourcc;

  /// DRM_FORMAT_MOD_* (AFBC/UBWC/linear)
  @ffi.Uint64()
  external int modifier;

  @ffi.Uint32()
  external int width;

  @ffi.Uint32()
  external int height;

  /// 1..LW_MAX_PLANES; validate before indexing
  @ffi.Uint32()
  external int num_planes;

  @ffi.Array.multi([4])
  external ffi.Array<LwDmabufPlane> planes;

  /// -1 none; non-owning. Normally -1: DQBUF
  /// implies decode complete. Reserved for
  /// future GPU-producer paths.
  @ffi.Int32()
  external int acquire_fence_fd;

  /// 0/90/180/270; RTP CVO passthrough
  @ffi.Uint32()
  external int rotation;

  /// for A/V sync + latency HUD
  @ffi.Int64()
  external int rtp_timestamp_us;

  /// monotonic within a session
  @ffi.Uint64()
  external int frame_seq;

  /// increments on pool reallocation; fd numbers
  /// are unique/stable only WITHIN a generation
  /// (kernel reuses fd values after pool close).
  /// Consumers key import caches on this.
  @ffi.Uint32()
  external int pool_generation;
}

/// The sink callback table. Registered with the sink registry and bound to a
/// track by token.
///
/// `size` is sizeof(LwVideoSinkV1): forward-compat gate for appended fields.
/// When the function shape must change, introduce LwVideoSinkV2.
final class LwVideoSinkV1 extends ffi.Struct {
  /// sizeof(LwVideoSinkV1)
  @ffi.Uint32()
  external int size;

  /// Called on the DECODER DELIVERY THREAD. MUST be non-blocking and
  /// allocation-free (do an SPSC POD handoff of desc + release pair).
  ///
  /// Consumer either:
  /// - TAKES the frame: stores `desc` BY VALUE, stores
  /// `release`+`release_ctx`, returns NONZERO. It now owns exactly one release
  /// obligation and MUST call `release(release_ctx)` exactly once.
  /// - DECLINES: returns 0. The producer releases the frame immediately
  /// (latest-wins drop). Declining is THE drop mechanism — it keeps the
  /// decoder unblocked; decode never stalls on presentation.
  external ffi.Pointer<
      ffi.NativeFunction<
          ffi.Int Function(
              ffi.Pointer<LwDmabufDescriptor> desc,
              LwFrameRelease release,
              ffi.Pointer<ffi.Void> release_ctx,
              ffi.Pointer<ffi.Void> user)>> on_frame;

  /// Announces the format/geometry of the generation that is about to begin.
  /// ALWAYS precedes the first on_frame of a new pool_generation.
  /// NORMATIVE: on this call the consumer MUST invalidate all cached imports
  /// from prior generations — fd numbers may be reused by the kernel across
  /// pool reallocation and are NOT identity. `fmt_only` carries a valid
  /// descriptor with no live fds to import.
  external ffi.Pointer<
      ffi.NativeFunction<
          ffi.Void Function(ffi.Pointer<LwDmabufDescriptor> fmt_only,
              ffi.Pointer<ffi.Void> user)>> on_format;

  /// End of stream. No further on_frame for this binding.
  external ffi.Pointer<
      ffi.NativeFunction<ffi.Void Function(ffi.Pointer<ffi.Void> user)>> on_eos;
}

/// Invoked by the consumer exactly once when it is done with a taken frame
/// (scanout out-fence signaled / wl_buffer.release). Maps to producer
/// re-QBUF. release_ctx is the cookie the producer handed to on_frame.
typedef LwFrameRelease
    = ffi.Pointer<ffi.NativeFunction<LwFrameReleaseFunction>>;
typedef LwFrameReleaseFunction = ffi.Void Function(
    ffi.Pointer<ffi.Void> release_ctx);
typedef DartLwFrameReleaseFunction = void Function(
    ffi.Pointer<ffi.Void> release_ctx);

final class lw_factory extends ffi.Opaque {}

/// Opaque handle to a peer-connection factory.
typedef lw_factory_t = lw_factory;

final class lw_video_track extends ffi.Opaque {}

/// Unguessable, nonzero handle to a registered video sink. 0 is invalid.
typedef lw_video_sink_token = ffi.Uint64;
typedef Dartlw_video_sink_token = int;

/// Opaque handle to a video track, produced by the control-plane shim.
typedef lw_video_track_t = lw_video_track;

/// Per-decoded-frame callback (fires on the decoder delivery thread) reporting
/// the frame's pixel dimensions. For counting/telemetry only -- the frame
/// itself never crosses here (native frames flow through the sink registry).
/// Must return promptly and must not re-enter the track API (it runs on the
/// delivery path). Pass cb = NULL to clear.
typedef lw_frame_cb = ffi.Pointer<ffi.NativeFunction<lw_frame_cbFunction>>;
typedef lw_frame_cbFunction = ffi.Void Function(
    ffi.Int width, ffi.Int height, ffi.Pointer<ffi.Void> user);
typedef Dartlw_frame_cbFunction = void Function(
    int width, int height, ffi.Pointer<ffi.Void> user);

final class lw_pc extends ffi.Opaque {}

final class lw_transceiver extends ffi.Opaque {}

