/// Per-event C callbacks, invoked on the signaling thread. Any field may be
/// NULL. State ints take the values of the enums above. The
/// struct is copied on registration, so it need not outlive the call; the
/// function pointers and `user` must remain valid until the observer is
/// removed.
final class LwPcObserver extends ffi.Struct {
  /// sizeof(LwPcObserver)
  @ffi.Uint32()
  external int size;

  external ffi.Pointer<
          ffi.NativeFunction<
              ffi.Void Function(ffi.Int state, ffi.Pointer<ffi.Void> user)>>
      on_signaling_state;

  external ffi.Pointer<
          ffi.NativeFunction<
              ffi.Void Function(ffi.Int state, ffi.Pointer<ffi.Void> user)>>
      on_connection_state;

  external ffi.Pointer<
          ffi.NativeFunction<
              ffi.Void Function(ffi.Int state, ffi.Pointer<ffi.Void> user)>>
      on_ice_gathering_state;

  external ffi.Pointer<
          ffi.NativeFunction<
              ffi.Void Function(ffi.Int state, ffi.Pointer<ffi.Void> user)>>
      on_ice_connection_state;

  /// A local ICE candidate was gathered. The strings are owned by the callback
  /// (lw_string_free), as for the SDP callbacks above.
  external ffi.Pointer<
      ffi.NativeFunction<
          ffi.Void Function(
              ffi.Pointer<ffi.Char> candidate,
              ffi.Pointer<ffi.Char> sdp_mid,
              ffi.Int sdp_mline_index,
              ffi.Pointer<ffi.Void> user)>> on_ice_candidate;

  external ffi.Pointer<
          ffi.NativeFunction<ffi.Void Function(ffi.Pointer<ffi.Void> user)>>
      on_renegotiation_needed;

  /// A remote track arrived. `transceiver` is an OWNING handle: retire it with
  /// lw_release; reach its receiver/video track via the transceiver
  /// accessors.
  external ffi.Pointer<
      ffi.NativeFunction<
          ffi.Void Function(ffi.Pointer<lw_transceiver_t> transceiver,
              ffi.Pointer<ffi.Void> user)>> on_track;
}

const int LW_ABI_VERSION = 3;

const int LW_MAX_PLANES = 4;
